export const meta = {
  name: 'divergence-complexity-audit',
  description: 'Three-lens audit (critical analyst, system architect, forward-deployed engineer) of the insurance claims take-home: what diverged from the assignment, and what complexity to cut',
  phases: [
    { title: 'Three-lens analysis' },
    { title: 'Synthesis & cut-list' },
  ],
}

const REPO = '/Users/raunaksingh/Documents/realfast/insurance'

// Grounding facts established by inline scouting — passed to every agent so they don't re-derive,
// but they MUST verify by reading the actual files and cite specific paths/lines.
const GROUNDING = `
PROJECT: Insurance "Claims Processing System" take-home assignment. Repo root: ${REPO}

ASSIGNMENT (read these to know the BAR):
- project-docs/candidate_assignment_instructions.md  (how it's graded; rejection criteria)
- project-docs/problem_statement.md  (the actual problem + in/out scope)

GROUND TRUTH established by scouting (VERIFY, then build on it):
- The assignment's #1 ground rule: "Ship a WORKING application, not just a passing test suite." Reviewers clone + run it.
- TDD is REQUIRED: git history must show tests appearing BEFORE/alongside code. Tests must encode domain rules, not HTTP status codes.
- JSONL session logs for EVERY phase (framing, research, planning, coding, docs, testing, QA) are MANDATORY — missing/partial logs = automatic rejection.
- "A system that does 3 things well beats one that does 10 things poorly." Out-of-scope work "will not improve your score."

CURRENT STATE OF THE REPO (the divergence):
- app/src has 49 .ts files — EVERY ONE is a 1-line comment-only placeholder. ZERO real code.
- app/tests/ contains only .gitkeep. ZERO tests written.
- Only ONE .jsonl log exists (ai-artifacts/01-framing/...). No coding/testing/QA/docs logs.
- Documentation is enormous and rich: PRD.md (219 lines), TRACK.md (100), AGENTS.md (144), README.md (81),
  docs/domain-model.md (249), docs/decisions.md (262), docs/adjudication-plan.md (323), docs/erd.md (247),
  docs/scenarios-flowchart.md (400), docs/self-review.md (60), plus 3 research md files.
- infographics/ has 4 SVGs + a 718-line visual-reference.html (1222 lines total of decoration).
- Speced infra/architecture (all still stubs): Drizzle ORM + SQLite migrations + drizzle-kit, Swagger/OpenAPI
  (app/src/docs/openapi.ts), a repositories layer (4 repos), a separate schemas layer (14 schema files split
  entities/ + api/), first-class DISPUTES with 4-value outcomes + accumulator net-out, a status-transition audit log.
- PRD scope ("In scope (7)"): submit claim, adjudicate line items in fixed order, compute payable cents
  (deductible/copay/coinsurance/limits/OOP-max), 2 state machines, claim-level aggregation, explanations,
  AND member disputes (re-adjudication with corrected facts + 4-value outcome). 4 REST endpoints.
- Time budget for the whole assignment: 24-48 hours. Nothing executable has been built yet.

NUANCE you must respect:
- Much of the DOMAIN modeling is GOOD and is exactly what the rubric rewards (discriminated cost-share union,
  unit-typed limits, accumulators, two state machines, reason codes + explanations). Do NOT recommend cutting
  genuine domain richness that the rubric scores.
- The problem is the RATIO: ~3600 lines of docs/visuals + heavy infra plans vs 0 lines of working code + 0 tests.
- Distinguish (a) pure overhead with no rubric value, (b) real-but-non-core features that can DEFER to v2,
  (c) core features to KEEP, (d) docs to CONSOLIDATE.
`

const PERSPECTIVE_SCHEMA = {
  type: 'object',
  additionalProperties: false,
  required: ['perspective', 'headline', 'divergences', 'complexity_to_remove', 'what_to_keep', 'top_recommendation'],
  properties: {
    perspective: { type: 'string' },
    headline: { type: 'string', description: 'One-sentence top-level takeaway from this lens' },
    divergences: {
      type: 'array',
      description: 'Ways the current accumulated work has drifted from the assignment intent/rules',
      items: {
        type: 'object',
        additionalProperties: false,
        required: ['title', 'evidence', 'severity', 'rule_violated'],
        properties: {
          title: { type: 'string' },
          evidence: { type: 'string', description: 'Specific file paths / line counts / git facts' },
          severity: { type: 'string', enum: ['critical', 'high', 'medium', 'low'] },
          rule_violated: { type: 'string', description: 'Which assignment rule/criterion this breaks' },
        },
      },
    },
    complexity_to_remove: {
      type: 'array',
      description: 'Specific things adding complexity that could be cut/deferred/consolidated',
      items: {
        type: 'object',
        additionalProperties: false,
        required: ['item', 'location', 'verdict', 'rationale', 'rubric_impact'],
        properties: {
          item: { type: 'string' },
          location: { type: 'string', description: 'File/dir path(s)' },
          verdict: { type: 'string', enum: ['CUT', 'DEFER', 'CONSOLIDATE', 'KEEP'] },
          rationale: { type: 'string' },
          rubric_impact: { type: 'string', description: 'Effect on score if removed: none/positive/negative and why' },
        },
      },
    },
    what_to_keep: { type: 'array', items: { type: 'string' }, description: 'Genuine strengths / core to preserve' },
    top_recommendation: { type: 'string', description: 'The single most important action from this lens' },
  },
}

phase('Three-lens analysis')

const LENSES = [
  {
    key: 'critical-analyst',
    role: 'CRITICAL ANALYST',
    charter: `You are a skeptical critical analyst reviewing a take-home submission-in-progress. Your job: name, bluntly and specifically, every way this work has DIVERGED from what the assignment actually rewards and what gets it REJECTED. Be adversarial — assume the reviewer is looking for reasons to reject. Focus on: the "ship a working app" ground rule, the TDD-before-code requirement, the mandatory per-phase JSONL logs, and the "3 things well > 10 poorly" principle. Quantify the doc-to-code ratio. Call out where effort went to things the rubric explicitly does NOT score (infographics, out-of-scope features, doc duplication/drift). Rank by how likely each is to sink the submission.`,
  },
  {
    key: 'system-architect',
    role: 'SYSTEM ARCHITECT',
    charter: `You are a system architect assessing structural complexity vs. the brief's actual scope (4 endpoints, adjudication, 2 state machines, explanations, optional disputes). Identify abstraction layers and infrastructure that are unnecessary or premature for a take-home that must SHIP and RUN in 24-48h: e.g. Drizzle ORM + migrations vs in-memory/better-sqlite3, a full repositories layer, a split schemas layer (entities/ + api/), Swagger/OpenAPI, disputes-as-first-class with accumulator net-out, status-transition audit log. For each, judge: does it earn its complexity given the rubric, or is it ceremony? Propose the MINIMAL architecture that still demonstrates clean domain decomposition. Respect that genuine domain richness (cost-share union, accumulators, state machines, reason codes) is the point and must stay.`,
  },
  {
    key: 'fde',
    role: 'FORWARD DEPLOYED ENGINEER',
    charter: `You are a pragmatic forward-deployed engineer with a 24-48h clock and ZERO working code written so far. Your only goal: a running, demonstrable system that nails the core loop (submit claim -> adjudicate line items in fixed order -> compute payable cents -> aggregate claim status -> explain decisions) with real tests written test-first. Produce a ruthless cut-list: what to drop NOW to make the deadline, what to defer to a documented v2, and the exact build order. Treat disputes, audit log, ORM/migrations, swagger, repos layer, and infographics as candidates for the chopping block unless they're cheaper to keep than cut. Be concrete about sequencing so tests land before code in git history.`,
  },
]

const analyses = await parallel(LENSES.map(lens => () =>
  agent(
    `${GROUNDING}

YOUR LENS: ${lens.role}
${lens.charter}

INSTRUCTIONS:
1. Read the two assignment files first to anchor on the BAR.
2. Read PRD.md and skim docs/ (domain-model, decisions, adjudication-plan, erd, scenarios-flowchart) and the app/src tree + git log to confirm the ground-truth state. Verify the "all stubs / no tests / one jsonl" facts yourself.
3. Produce findings strictly through YOUR lens. Be specific — cite file paths and counts. No generic advice.
4. Every complexity_to_remove item needs a clear verdict (CUT/DEFER/CONSOLIDATE/KEEP) and an honest rubric_impact.
Return ONLY the structured object.`,
    { label: lens.role, phase: 'Three-lens analysis', schema: PERSPECTIVE_SCHEMA }
  )
)).then(rs => rs.filter(Boolean))

phase('Synthesis & cut-list')

const SYNTH_SCHEMA = {
  type: 'object',
  additionalProperties: false,
  required: ['executive_summary', 'the_core_problem', 'divergences_ranked', 'cut_list', 'recommended_minimal_scope', 'build_order', 'safe_to_delete_now', 'needs_user_decision'],
  properties: {
    executive_summary: { type: 'string', description: '3-5 sentence verdict a busy person can act on' },
    the_core_problem: { type: 'string', description: 'The one root cause in 1-2 sentences' },
    divergences_ranked: {
      type: 'array',
      items: {
        type: 'object',
        additionalProperties: false,
        required: ['rank', 'title', 'severity', 'evidence', 'why_it_matters'],
        properties: {
          rank: { type: 'number' },
          title: { type: 'string' },
          severity: { type: 'string', enum: ['critical', 'high', 'medium', 'low'] },
          evidence: { type: 'string' },
          why_it_matters: { type: 'string' },
        },
      },
    },
    cut_list: {
      type: 'array',
      description: 'Deduped, merged complexity items with a single agreed verdict',
      items: {
        type: 'object',
        additionalProperties: false,
        required: ['item', 'location', 'verdict', 'rationale', 'consensus'],
        properties: {
          item: { type: 'string' },
          location: { type: 'string' },
          verdict: { type: 'string', enum: ['CUT', 'DEFER', 'CONSOLIDATE', 'KEEP'] },
          rationale: { type: 'string' },
          consensus: { type: 'string', description: 'Did all 3 lenses agree? Note any disagreement.' },
        },
      },
    },
    recommended_minimal_scope: {
      type: 'object',
      additionalProperties: false,
      required: ['keep', 'cut', 'defer'],
      properties: {
        keep: { type: 'array', items: { type: 'string' } },
        cut: { type: 'array', items: { type: 'string' } },
        defer: { type: 'array', items: { type: 'string' } },
      },
    },
    build_order: { type: 'array', items: { type: 'string' }, description: 'TDD-first sequence to a running system' },
    safe_to_delete_now: { type: 'array', items: { type: 'string' }, description: 'Specific files/dirs with ZERO rubric value, safe to delete immediately' },
    needs_user_decision: { type: 'array', items: { type: 'string' }, description: 'Cuts that are judgment calls the user must confirm before deleting (e.g. disputes, ORM)' },
  },
}

const synthesis = await agent(
  `${GROUNDING}

You are the lead synthesizer. Three independent analysts examined this repo through different lenses. Merge their findings into ONE actionable report. Dedupe overlapping points, resolve disagreements (note them), and rank by impact on the submission outcome.

CRITICAL DISTINCTION you must enforce in the cut_list and scope:
- CUT = pure overhead, no rubric value, delete now (e.g. infographics, swagger).
- DEFER = real feature but not core; document as v2 (candidates: disputes, status-transition audit log, OOP-max if it bloats).
- CONSOLIDATE = redundant docs to merge (erd + scenarios-flowchart likely fold into domain-model).
- KEEP = genuine domain richness the rubric scores (cost-share union, accumulators, 2 state machines, reason codes, explanations, the core adjudication loop).
Separate "safe_to_delete_now" (no judgment needed) from "needs_user_decision" (destructive cuts to confirm first — anything in the locked PRD scope, anything reflecting real domain work).

The build_order must be TDD-first so git history shows tests before code, and must get to a RUNNING demonstrable system fast.

THE THREE ANALYSES (JSON):
${JSON.stringify(analyses, null, 2)}

Return ONLY the structured object.`,
  { label: 'synthesis', phase: 'Synthesis & cut-list', schema: SYNTH_SCHEMA }
)

return { analyses, synthesis }

